import React from "react";
import { Box, Heading, Stack, Text } from "@chakra-ui/react";
import LandingPageCarousel from "../../Pages/LandingPageComponents/LandingPageCarousel";
import InProgressCarousel from "./InProgressCarousel";

const Section = ({ title, subtitle, children }) => {
  return (
    <Box mb={10}>
      <Stack spacing={2} mb={4}>
        <Heading as="h2" size="lg" fontWeight="bold" color="#1c1d1f">
          {title}
        </Heading>

        {subtitle && (
          <Text fontSize="sm" color="gray.600">
            {subtitle}
          </Text>
        )}
      </Stack>

      <Box bg="#f7f9fa" p={4} borderRadius="12px">
        {children}
      </Box>
    </Box>
  );
};

const CourseComponent = () => {
  return (
    <Box px={{ base: 4, md: 8 }} py={6}>
      
      {/* All Courses */}
      <Section
        title="All Courses"
        subtitle="Explore our most popular courses"
      >
        <LandingPageCarousel category="all" />
      </Section>

      {/* In Progress */}
      <Section
        title="In Progress Courses"
        subtitle="Continue where you left off"
      >
        <InProgressCarousel />
      </Section>

      {/* Business */}
      <Section title="Top courses in Business">
        <LandingPageCarousel category="business" />
      </Section>

      {/* IT */}
      <Section title="Top courses in IT & Software">
        <LandingPageCarousel category="it" />
      </Section>

      {/* Personal */}
      <Section title="Top courses in Personal Development">
        <LandingPageCarousel category="personal" />
      </Section>

    </Box>
  );
};

export default CourseComponent;
